namespace {

    struct Edge{

        int dst, cost;

    };

    typedef vector<Edge> Node;

    typedef vector<Node> Graph;

    Graph G;

    typedef tuple<int, int, int> TP;

    vector<TP> es;

    vector<bool> is_base;

    int N, T, K;



    set<int> used[10000];



    bool find(int u, int p) {

        if(is_base[u]) return true;

        for(Edge e : G[u]) {

            if(e.dst == p) continue;

            if(used[u].count(e.dst)) continue;

            if(find(e.dst, u)) return true;

        }

        return false;

    }



    int solve() {

        REP(i, N) used[i].clear();

        int ans = 0;

        for(auto tp : es) {

            if(K == 0) break;

            int w, a, b;

            tie(w, a, b) = tp;

            if(find(a, b) && find(b, a)) {

                K--;

                ans += w;

                used[a].insert(b);

                used[b].insert(a);

            }

        }

        return ans;

    }

}





