    iostream_init();

    int Case = 0;

    while(cin >> N >> T >> K && N > 0) {

        cout << "Case " << ++Case << ": ";

        G.assign(N, Node());

        es.clear();

        is_base.assign(N, false);



        REP(i, N-1) {

            int a, b, w;

            cin >> a >> b >> w;

            a--; b--;

            G[a].push_back({b, w});

            G[b].push_back({a, w});

